1	import mongoose, { Schema, Document, Model } from 'mongoose';
2	import { ITest, IQuestion, IRelatedContent, IMatchingItem } from '../types';
3	import { ENT_QUESTION_TYPES, validateEntQuestion } from '../utils/entQuestion.util';
4	
5	const RelatedContentSchema = new Schema<IRelatedContent>(
6	  {
7	    chapterId: {
8	      type: Schema.Types.ObjectId
9	    },
10	    topicId: {
11	      type: Schema.Types.ObjectId
12	    },
13	    pages: [
14	      {
15	        type: Number,
16	        required: true
17	      }
18	    ],
19	    topicTitle: { type: String, trim: true }
20	  },
21	  { _id: false }
22	);
23	
24	const MatchingItemSchema = new Schema<IMatchingItem>(
25	  {
26	    id: { type: String, required: true, trim: true },
27	    text: { type: String, required: true, trim: true }
28	  },
29	  { _id: false }
30	);
31	
32	const QuestionSchema = new Schema<IQuestion>(
33	  {
34	    questionType: {
35	      type: String,
36	      enum: [...ENT_QUESTION_TYPES],
37	      default: 'single_choice'
38	    },
39	    questionText: {
40	      type: String,
41	      required: true,
42	      trim: true,
43	      minlength: 5,
44	      maxlength: 2000
45	    },
46	    options: [{ type: String, trim: true }],
47	    correctOption: { type: String, trim: true },
48	    correctOptions: [{ type: String, trim: true }],
49	    matchingLeft: [MatchingItemSchema],
50	    matchingRight: [MatchingItemSchema],
51	    correctMatching: { type: Schema.Types.Mixed },
52	    acceptableAnswers: [{ type: String, trim: true }],
53	    acceptableKeywords: [{ type: String, trim: true }],
54	    referenceAnswer: { type: String, trim: true },
55	    aiExplanation: {
56	      type: String,
57	      required: true,
58	      trim: true,
59	      maxlength: 1200
60	    },
61	    relatedContent: {
62	      type: RelatedContentSchema,
63	      required: true
64	    },
65	    /** Банк (Фаза 2/3): id item банка и покрытые KC — для статистики/SR/пер-KC mastery */
66	    questionItemId: { type: Schema.Types.ObjectId },
67	    knowledgeComponentIds: { type: [String], default: undefined }
68	  },
69	  { _id: false }
70	);
71	
72	type ITestDocument = Document & Omit<ITest, '_id'>;
73	
74	const TestSchema = new Schema<ITestDocument>(
75	  {
76	    subjectId: {
77	      type: Schema.Types.ObjectId,
78	      ref: 'Subject',
79	      required: true,
80	      index: true
81	    },
82	    bookId: {
83	      type: Schema.Types.ObjectId,
84	      required: true,
85	      index: true
86	    },
87	    chapterId: {
88	      type: Schema.Types.ObjectId,
89	      index: true
90	    },
91	    questions: [QuestionSchema],
92	    sourceContentHash: {
93	      type: String,
94	      required: true,
95	      index: true
96	    },
97	    testProfile: {
98	      type: String,
99	      enum: ['regular', 'ent'],
100	      default: 'ent'
101	    }
102	  },
103	  {
104	    timestamps: true,
105	    collection: 'tests'
106	  }
107	);
108	
109	TestSchema.index({ subjectId: 1, bookId: 1, chapterId: 1, sourceContentHash: 1, testProfile: 1 });
110	TestSchema.index({ createdAt: -1 });
111	
112	TestSchema.path('questions').validate(
113	  (questions: IQuestion[]) => {
114	    // Размер теста переменный (regular/ent/банк): валидируем диапазон + корректность каждого вопроса.
115	    if (!Array.isArray(questions) || questions.length < 1 || questions.length > 120) return false;
116	    try {
117	      questions.forEach((q, i) => {
118	        validateEntQuestion(q as unknown, i);
119	      });
120	      return true;
121	    } catch {
122	      return false;
123	    }
124	  },
125	  'Тест должен содержать 1–120 корректных вопросов в формате ЕНТ'
126	);
127	
128	TestSchema.statics.findCachedTest = async function (
129	  subjectId: string,
130	  bookId: string,
131	  chapterId: string | undefined,
132	  sourceContentHash: string
133	) {
134	  const query: Record<string, unknown> = {
135	    subjectId,
136	    bookId,
137	    sourceContentHash
138	  };
139	
140	  if (chapterId) {
141	    query.chapterId = chapterId;
142	  } else {
143	    query.chapterId = { $exists: false };
144	  }
145	
146	  return this.findOne(query).sort({ createdAt: -1 });
147	};
148	
149	TestSchema.methods.getQuestionHashes = function (): string[] {
150	  return this.questions.map((q: IQuestion) => Buffer.from(q.questionText).toString('base64'));
151	};
152	
153	export const Test: Model<ITestDocument> = mongoose.model<ITestDocument>('Test', TestSchema);
154

